const svg = document.getElementById('ch-svg');
const out = document.getElementById('ch-out');
const lam = document.getElementById('ch-lam');
const phi = document.getElementById('ch-phi');
function draw(){
  svg.innerHTML = '';
  // left panel: sphere
  const cx1=140, cy1=160, R=110;
  // axonometric ellipse hint for sphere
  svg.appendChild(SVG('circle',{cx:cx1,cy:cy1,r:R,fill:'#0b0f16',stroke:'var(--line)','stroke-width':1.5}));
  svg.appendChild(SVG('ellipse',{cx:cx1,cy:cy1,rx:R,ry:R*0.32,fill:'none',stroke:'var(--line)','stroke-dasharray':'3 4'}));
  svg.appendChild(SVG('ellipse',{cx:cx1,cy:cy1,rx:R*0.7,ry:R*0.22,fill:'none',stroke:'var(--line)','stroke-dasharray':'3 4'}));
  svg.appendChild(SVG('ellipse',{cx:cx1,cy:cy1,rx:R*0.4,ry:R*0.12,fill:'none',stroke:'var(--line)','stroke-dasharray':'3 4'}));
  // meridians
  for(let k=0;k<6;k++){
    const rx = R*Math.cos(k*Math.PI/6);
    svg.appendChild(SVG('ellipse',{cx:cx1,cy:cy1,rx:Math.abs(rx)||0.5,ry:R,fill:'none',stroke:'var(--line)','stroke-dasharray':'2 5','opacity':0.6}));
  }
  // poles
  svg.appendChild(SVG('circle',{cx:cx1,cy:cy1-R,r:3.5,fill:'var(--cyan)'}));
  const tN = SVG('text',{x:cx1+8,y:cy1-R+4,'font-size':12,fill:'var(--cyan)'}); tN.textContent='N'; svg.appendChild(tN);
  svg.appendChild(SVG('circle',{cx:cx1,cy:cy1+R,r:3.5,fill:'var(--pink)'}));
  const tS = SVG('text',{x:cx1+8,y:cy1+R+4,'font-size':12,fill:'var(--pink)'}); tS.textContent='S'; svg.appendChild(tS);

  const L = +lam.value * Math.PI/180;
  const P = +phi.value * Math.PI/180;
  // axonometric projection of (cos L cos P, sin L cos P, sin P)
  const X = Math.cos(L)*Math.cos(P);
  const Y = Math.sin(L)*Math.cos(P);
  const Z = Math.sin(P);
  // 3D to 2D: x_screen = cx + R*X, y_screen = cy - R*Z + R*Y*0.3
  const sx = cx1 + R*X;
  const sy = cy1 - R*Z + R*Y*0.32;
  svg.appendChild(SVG('circle',{cx:sx,cy:sy,r:5,fill:'var(--yellow)',stroke:'#111','stroke-width':1}));
  const tp = SVG('text',{x:sx+8,y:sy-8,'font-size':12,fill:'var(--yellow)'}); tp.textContent='p'; svg.appendChild(tp);

  // middle panel: north chart disk
  const cx2=440, cy2=160, Rc=100;
  svg.appendChild(SVG('rect',{x:cx2-Rc-10,y:cy2-Rc-10,width:(Rc+10)*2,height:(Rc+10)*2,fill:'#0b0f16',stroke:'var(--line)',rx:6}));
  svg.appendChild(SVG('circle',{cx:cx2,cy:cy2,r:Rc,fill:'none',stroke:'var(--line)','stroke-dasharray':'2 4'}));
  // crosshair
  svg.appendChild(SVG('line',{x1:cx2-Rc-4,y1:cy2,x2:cx2+Rc+4,y2:cy2,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:cx2,y1:cy2-Rc-4,x2:cx2,y2:cy2+Rc+4,stroke:'var(--line)'}));
  // stereographic from N: u = X/(1-Z), v = Y/(1-Z)
  let uN, vN;
  if(Z < 0.999){ uN = X/(1-Z); vN = Y/(1-Z); }
  else { uN = Infinity; vN = Infinity; }
  const scale = Rc/2.2;
  if(isFinite(uN)){
    const px = cx2 + uN*scale, py = cy2 - vN*scale;
    if(Math.abs(uN)<5 && Math.abs(vN)<5){
      svg.appendChild(SVG('circle',{cx:px,cy:py,r:5,fill:'var(--yellow)',stroke:'#111','stroke-width':1}));
    } else {
      // clipped — show arrow at edge
      const ang = Math.atan2(-vN, uN);
      svg.appendChild(SVG('circle',{cx:cx2+Math.cos(ang)*Rc,cy:cy2+Math.sin(ang)*Rc,r:4,fill:'var(--pink)'}));
    }
  }
  const lbl1 = SVG('text',{x:cx2,y:cy2-Rc-16,'text-anchor':'middle','font-size':12,fill:'var(--cyan)'});
  lbl1.textContent = 'φ_N : S²\\{N} → ℝ²';
  svg.appendChild(lbl1);

  // right panel: south chart
  const cx3=720, cy3=160;
  svg.appendChild(SVG('rect',{x:cx3-Rc-10,y:cy3-Rc-10,width:(Rc+10)*2,height:(Rc+10)*2,fill:'#0b0f16',stroke:'var(--line)',rx:6}));
  svg.appendChild(SVG('circle',{cx:cx3,cy:cy3,r:Rc,fill:'none',stroke:'var(--line)','stroke-dasharray':'2 4'}));
  svg.appendChild(SVG('line',{x1:cx3-Rc-4,y1:cy3,x2:cx3+Rc+4,y2:cy3,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:cx3,y1:cy3-Rc-4,x2:cx3,y2:cy3+Rc+4,stroke:'var(--line)'}));
  let uS, vS;
  if(Z > -0.999){ uS = X/(1+Z); vS = Y/(1+Z); }
  else { uS = Infinity; vS = Infinity; }
  if(isFinite(uS)){
    const px = cx3 + uS*scale, py = cy3 - vS*scale;
    if(Math.abs(uS)<5 && Math.abs(vS)<5){
      svg.appendChild(SVG('circle',{cx:px,cy:py,r:5,fill:'var(--yellow)',stroke:'#111','stroke-width':1}));
    } else {
      const ang = Math.atan2(-vS, uS);
      svg.appendChild(SVG('circle',{cx:cx3+Math.cos(ang)*Rc,cy:cy3+Math.sin(ang)*Rc,r:4,fill:'var(--pink)'}));
    }
  }
  const lbl2 = SVG('text',{x:cx3,y:cy3-Rc-16,'text-anchor':'middle','font-size':12,fill:'var(--pink)'});
  lbl2.textContent = 'φ_S : S²\\{S} → ℝ²';
  svg.appendChild(lbl2);

  // transition annotations
  const r2 = uN*uN + vN*vN;
  const t2u = isFinite(uN) && r2>1e-9 ? uN/r2 : NaN;
  const t2v = isFinite(vN) && r2>1e-9 ? vN/r2 : NaN;
  out.textContent =
    `p on sphere: (x,y,z) = (${fmt(X)}, ${fmt(Y)}, ${fmt(Z)})\n`+
    `φ_N(p) = (u,v) = (${isFinite(uN)?fmt(uN):'∞'}, ${isFinite(vN)?fmt(vN):'∞'})\n`+
    `φ_S(p) = (u',v') = (${isFinite(uS)?fmt(uS):'∞'}, ${isFinite(vS)?fmt(vS):'∞'})\n`+
    `transition  φ_S∘φ_N⁻¹(u,v) = (u,v)/(u²+v²) = (${isFinite(t2u)?fmt(t2u):'—'}, ${isFinite(t2v)?fmt(t2v):'—'})`;
}
lam.addEventListener('input', draw);
phi.addEventListener('input', draw);
draw();

