const svg = document.getElementById('rk-svg');
const out = document.getElementById('rk-out');
const pick = document.getElementById('rk-pick');
const FUN = {
  id:   { f:(x,y)=>[x,y],      J:(x,y)=>[[1,0],[0,1]],    lbl:'(x, y)',      det:(x,y)=>1, full:2 },
  proj: { f:(x,y)=>[x,x],      J:(x,y)=>[[1,0],[1,0]],    lbl:'(x, x)',      det:(x,y)=>0, full:1 },
  xy:   { f:(x,y)=>[x*y,x+y],  J:(x,y)=>[[y,x],[1,1]],    lbl:'(xy, x+y)',   det:(x,y)=>y-x, full:2 },
  sq:   { f:(x,y)=>[x*x,y*y],  J:(x,y)=>[[2*x,0],[0,2*y]],lbl:'(x², y²)',    det:(x,y)=>4*x*y, full:2 },
};
function rankOf(J){
  const a=J[0][0], b=J[0][1], c=J[1][0], d=J[1][1];
  const n1 = Math.hypot(a,b), n2 = Math.hypot(c,d);
  if(n1<1e-9 && n2<1e-9) return 0;
  const det = a*d - b*c;
  if(Math.abs(det) > 1e-7) return 2;
  return 1;
}
function draw(){
  svg.innerHTML = '';
  const key = pick.value;
  const F = FUN[key];
  // domain panel
  const dx=40, dy=30, dw=340, dh=300;
  svg.appendChild(SVG('rect',{x:dx,y:dy,width:dw,height:dh,fill:'#0b0f16',stroke:'var(--line)',rx:6}));
  const cx=dx+dw/2, cy=dy+dh/2, S=dw/4.2; // scale so x,y in [-2,2]
  // axes
  svg.appendChild(SVG('line',{x1:dx,y1:cy,x2:dx+dw,y2:cy,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:cx,y1:dy,x2:cx,y2:dy+dh,stroke:'var(--line)'}));
  const lblD = SVG('text',{x:dx+8,y:dy+16,'font-size':12,fill:'var(--mute)'}); lblD.textContent='domain ℝ²'; svg.appendChild(lblD);
  // sample points
  const N=15;
  for(let i=0;i<N;i++) for(let j=0;j<N;j++){
    const x = -2 + 4*i/(N-1);
    const y = -2 + 4*j/(N-1);
    const J = F.J(x,y);
    const r = rankOf(J);
    const col = r===2 ? 'var(--green)' : (r===1 ? 'var(--yellow)' : 'var(--pink)');
    const px = cx + x*S, py = cy - y*S;
    svg.appendChild(SVG('circle',{cx:px,cy:py,r:3.2,fill:col,opacity:0.85}));
  }
  // image panel
  const rx=dx+dw+40, ry=dy, rw=340, rh=300;
  svg.appendChild(SVG('rect',{x:rx,y:ry,width:rw,height:rh,fill:'#0b0f16',stroke:'var(--line)',rx:6}));
  const rcx=rx+rw/2, rcy=ry+rh/2, RS=rw/8.5;
  svg.appendChild(SVG('line',{x1:rx,y1:rcy,x2:rx+rw,y2:rcy,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:rcx,y1:ry,x2:rcx,y2:ry+rh,stroke:'var(--line)'}));
  const lblR = SVG('text',{x:rx+8,y:ry+16,'font-size':12,'fill':'var(--mute)'}); lblR.textContent='image in ℝ²'; svg.appendChild(lblR);
  for(let i=0;i<N;i++) for(let j=0;j<N;j++){
    const x = -2 + 4*i/(N-1);
    const y = -2 + 4*j/(N-1);
    const J = F.J(x,y);
    const r = rankOf(J);
    const col = r===2 ? 'var(--green)' : (r===1 ? 'var(--yellow)' : 'var(--pink)');
    const [u,v] = F.f(x,y);
    if(Math.abs(u)<4.5 && Math.abs(v)<4.5){
      svg.appendChild(SVG('circle',{cx:rcx+u*RS,cy:rcy-v*RS,r:3.0,fill:col,opacity:0.7}));
    }
  }
  // legend
  const lg = [
    ['rank 2','var(--green)'],['rank 1','var(--yellow)'],['rank 0','var(--pink)']
  ];
  lg.forEach(([t,c],i)=>{
    svg.appendChild(SVG('circle',{cx:rx+rw-90,cy:ry+20+i*18,r:4,fill:c}));
    const tt = SVG('text',{x:rx+rw-80,y:ry+24+i*18,'font-size':12,fill:'var(--mute)'});
    tt.textContent = t; svg.appendChild(tt);
  });
  out.textContent =
    `f(x,y) = ${F.lbl}\n`+
    `Jacobian Df = ${JSON.stringify(F.J('x','y')).replace(/"/g,'')}\n`+
    `det Df at (1,1) = ${fmt(F.det(1,1))}   at (0,0) = ${fmt(F.det(0,0))}`;
}
pick.addEventListener('change', draw);
draw();

