// sphere (lat, lon) -> R^3
function sph(lam, phi){
  return [Math.cos(phi)*Math.cos(lam), Math.cos(phi)*Math.sin(lam), Math.sin(phi)];
}
// axonometric proj
function P(x,y,z){ return [x + 0.25*y, -z + 0.18*y]; }

// Vector fields given in (lam, phi) -> (Vlam, Vphi) angular speeds
const FIELDS = {
  lat: {
    name:'∂_φ (latitude / longitudinal flow)',
    zeros:[ [0, Math.PI/2], [0, -Math.PI/2] ],
    zlabel:['N','S'],
    info:'Flows along meridians from S to N. Zeros: both poles (rank drops).',
    vec:(lam,phi)=>{
      // velocity in R^3 of d/dphi at (lam,phi): derivative of sph wrt phi
      return [ -Math.sin(phi)*Math.cos(lam), -Math.sin(phi)*Math.sin(lam), Math.cos(phi) ];
    }
  },
  rot: {
    name:'rotation about z-axis (∂_λ)',
    zeros:[ [0, Math.PI/2], [0, -Math.PI/2] ],
    zlabel:['N','S'],
    info:'Flows along latitudes eastward. Zeros: both poles.',
    vec:(lam,phi)=>{
      // derivative of sph wrt lam: (-sin lam cos phi, cos lam cos phi, 0)
      return [ -Math.sin(lam)*Math.cos(phi), Math.cos(lam)*Math.cos(phi), 0 ];
    }
  },
  grad: {
    name:'∇f on S², f(x,y,z) = z',
    zeros:[ [0, Math.PI/2], [0, -Math.PI/2] ],
    zlabel:['N (max)','S (min)'],
    info:'Gradient of height. Points "upward along the sphere"; zero at poles.',
    vec:(lam,phi)=>{
      // grad on S^2 of z: cos(phi) * e_phi. In R^3 that is cos(phi) * (dsph/dphi)
      const c = Math.cos(phi);
      return [ c*(-Math.sin(phi)*Math.cos(lam)), c*(-Math.sin(phi)*Math.sin(lam)), c*Math.cos(phi) ];
    }
  }
};

function draw(){
  svg.innerHTML = '';
  const cx=400, cy=190, R=140;
  // sphere outline
  svg.appendChild(SVG('circle',{cx,cy,r:R,fill:'#0b0f16',stroke:'var(--line)'}));
  // latitude lines
  for(let phi=-60; phi<=60; phi+=30){
    const ph = phi*Math.PI/180;
    const pts = [];
    for(let lam=0; lam<=Math.PI*2+0.01; lam+=Math.PI/30){
      const p3 = sph(lam, ph);
      const [u,v] = P(...p3);
      pts.push([cx + u*R, cy + v*R]);
    }
    const d = pts.map((p,i)=>(i?'L':'M')+p[0]+' '+p[1]).join(' ');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--line)',opacity:0.5,'stroke-dasharray':'2 4'}));
  }
  // meridians
  for(let lam=0; lam<Math.PI*2; lam+=Math.PI/6){
    const pts = [];
    for(let phi=-Math.PI/2+0.01; phi<=Math.PI/2-0.01; phi+=Math.PI/30){
      const p3 = sph(lam, phi);
      const [u,v] = P(...p3);
      pts.push([cx + u*R, cy + v*R]);
    }
    const d = pts.map((p,i)=>(i?'L':'M')+p[0]+' '+p[1]).join(' ');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--line)',opacity:0.4}));
  }

  const F = FIELDS[current];
  // draw arrows on a grid of (lam, phi); only on front hemisphere
  for(let lam=0; lam<Math.PI*2; lam+=Math.PI/10){
    for(let phi=-Math.PI/2+0.15; phi<Math.PI/2; phi+=Math.PI/10){
      const p3 = sph(lam, phi);
      // only draw front-facing points: y-component positive means "back"? we use x from proj axis
      // front-facing: the axonometric camera direction ~ (0, -1, 0.18); visible if dot > 0
      const nDotCam = -p3[1] + 0.15*p3[2];
      if(nDotCam < -0.1) continue;
      const v3 = F.vec(lam, phi);
      const mag = Math.hypot(v3[0],v3[1],v3[2]);
      if(mag < 0.01) continue;
      const scale = 0.18 / Math.max(mag,0.1);
      const q3 = [p3[0]+v3[0]*scale, p3[1]+v3[1]*scale, p3[2]+v3[2]*scale];
      const [u1,v1] = P(...p3);
      const [u2,v2] = P(...q3);
      const A = [cx+u1*R, cy+v1*R];
      const B = [cx+u2*R, cy+v2*R];
      drawArrow(svg, A, B, {color:'var(--cyan)',markerId:'vf-a',width:1.2,pad1:0,pad2:3});
    }
  }

  // draw zeros
  F.zeros.forEach((z,i)=>{
    const p3 = sph(z[0], z[1]);
    const [u,v] = P(...p3);
    const nDotCam = -p3[1] + 0.15*p3[2];
    const col = nDotCam < -0.1 ? 'var(--line)' : 'var(--pink)';
    svg.appendChild(SVG('circle',{cx:cx+u*R, cy:cy+v*R, r:6, fill:col, stroke:'#111','stroke-width':1.5}));
    const t = SVG('text',{x:cx+u*R+9,y:cy+v*R+4,'font-size':12,fill:col});
    t.textContent = F.zlabel[i] || 'zero'; svg.appendChild(t);
  });

  // side text
  const lines = [
    F.name,
    '',
    'Number of zeros: '+F.zeros.length,
    'χ(S²) = 2 (Poincaré–Hopf)',
    '',
    F.info
  ];
  lines.forEach((s,i)=>{
    const t = SVG('text',{x:590,y:40+i*20,'font-size':12,fill:'var(--mute)'});
    t.textContent = s; svg.appendChild(t);
  });

  out.textContent = `field: ${F.name}\nzeros detected: ${F.zeros.length}\n${F.info}`;
}
draw();

