// axonometric proj
function P(x,y,z){ return [x + 0.25*y, -z + 0.18*y]; }

// Vector fields given in (lam, phi) -> (Vlam, Vphi) angular speeds
const FIELDS = {
  lat: {
    name:'∂_φ (latitude / longitudinal flow)',
    zeros:[ [0, Math.PI/2], [0, -Math.PI/2] ],
    zlabel:['N','S'],
    info:'Flows along meridians from S to N. Zeros: both poles (rank drops).',
    vec:(lam,phi)=>{
      // velocity in R^3 of d/dphi at (lam,phi): derivative of sph wrt phi
      return [ -Math.sin(phi)*Math.cos(lam), -Math.sin(phi)*Math.sin(lam), Math.cos(phi) ];
    }
  },
  rot: {
    name:'rotation about z-axis (∂_λ)',
    zeros:[ [0, Math.PI/2], [0, -Math.PI/2] ],
    zlabel:['N','S'],
    info:'Flows along latitudes eastward. Zeros: both poles.',
    vec:(lam,phi)=>{
      // derivative of sph wrt lam: (-sin lam cos phi, cos lam cos phi, 0)
      return [ -Math.sin(lam)*Math.cos(phi), Math.cos(lam)*Math.cos(phi), 0 ];
    }
  },
  grad: {
    name:'∇f on S², f(x,y,z) = z',
    zeros:[ [0, Math.PI/2], [0, -Math.PI/2] ],
    zlabel:['N (max)','S (min)'],
    info:'Gradient of height. Points "upward along the sphere"; zero at poles.',
    vec:(lam,phi)=>{
      // grad on S^2 of z: cos(phi) * e_phi. In R^3 that is cos(phi) * (dsph/dphi)
      const c = Math.cos(phi);
      return [ c*(-Math.sin(phi)*Math.cos(lam)), c*(-Math.sin(phi)*Math.sin(lam)), c*Math.cos(phi) ];
    }
  }
};

function draw(){
  svg.innerHTML = '';
  const cx=400, cy=190, R=140;
  // sphere outline
  svg.appendChild(SVG('circle',{cx,cy,r:R,fill:'#0b0f16',stroke:'var(--line)'}));
  // latitude lines
  for(let phi=-60; phi<=60; phi+=30){
    const ph = phi*Math.PI/180;
    const pts = [];
    for(let lam=0; lam<=Math.PI*2+0.01; lam+=Math.PI/30){
      const p3 = sph(lam, ph);
      const [u,v] = P(...p3);
      pts.push([cx + u*R, cy + v*R]);
    }
    const d = pts.map((p,i)=>(i?'L':'M')+p[0]+' '+p[1]).join(' ');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--line)',opacity:0.5,'stroke-dasharray':'2 4'}));
  }
  // meridians
  for(let lam=0; lam<Math.PI*2; lam+=Math.PI/6){
    const pts = [];
    for(let phi=-Math.PI/2+0.01; phi<=Math.PI/2-0.01; phi+=Math.PI/30){
      const p3 = sph(lam, phi);
      const [u,v] = P(...p3);
      pts.push([cx + u*R, cy + v*R]);
    }
    const d = pts.map((p,i)=>(i?'L':'M')+p[0]+' '+p[1]).join(' ');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--line)',opacity:0.4}));
  }

  const F = FIELDS[current];
  // draw arrows on a grid of (lam, phi); only on front hemisphere
  for(let lam=0; lam<Math.PI*2; lam+=Math.PI/10){
    for(let phi=-Math.PI/2+0.15; phi<Math.PI/2; phi+=Math.PI/10){
      const p3 = sph(lam, phi);
      // only draw front-facing points: y-component positive means "back"? we use x from proj axis
      // front-facing: the axonometric camera direction ~ (0, -1, 0.18); visible if dot > 0
      const nDotCam = -p3[1] + 0.15*p3[2];
      if(nDotCam < -0.1) continue;
      const v3 = F.vec(lam, phi);
      const mag = Math.hypot(v3[0],v3[1],v3[2]);
      if(mag < 0.01) continue;
      const scale = 0.18 / Math.max(mag,0.1);
      const q3 = [p3[0]+v3[0]*scale, p3[1]+v3[1]*scale, p3[2]+v3[2]*scale];
      const [u1,v1] = P(...p3);
      const [u2,v2] = P(...q3);
      const A = [cx+u1*R, cy+v1*R];
      const B = [cx+u2*R, cy+v2*R];
      drawArrow(svg, A, B, {color:'var(--cyan)',markerId:'vf-a',width:1.2,pad1:0,pad2:3});
    }
  }

  // draw zeros
  F.zeros.forEach((z,i)=>{
    const p3 = sph(z[0], z[1]);
    const [u,v] = P(...p3);
    const nDotCam = -p3[1] + 0.15*p3[2];
    const col = nDotCam < -0.1 ? 'var(--line)' : 'var(--pink)';
    svg.appendChild(SVG('circle',{cx:cx+u*R, cy:cy+v*R, r:6, fill:col, stroke:'#111','stroke-width':1.5}));
    const t = SVG('text',{x:cx+u*R+9,y:cy+v*R+4,'font-size':12,fill:col});
    t.textContent = F.zlabel[i] || 'zero'; svg.appendChild(t);
  });

  // side text
  const lines = [
    F.name,
    '',
    'Number of zeros: '+F.zeros.length,
    'χ(S²) = 2 (Poincaré–Hopf)',
    '',
    F.info
  ];
  lines.forEach((s,i)=>{
    const t = SVG('text',{x:590,y:40+i*20,'font-size':12,fill:'var(--mute)'});
    t.textContent = s; svg.appendChild(t);
  });

  out.textContent = `field: ${F.name}\nzeros detected: ${F.zeros.length}\n${F.info}`;
}
draw();

const svg = document.getElementById('fl-svg');
const out = document.getElementById('fl-out');
const tSl = document.getElementById('fl-t');
const tLbl = document.getElementById('fl-tv');
const btns = [...document.querySelectorAll('#w-flow button[data-fl]')];
let current = 'rot';
let p0 = [1.0, 0.0];
btns.forEach(b => b.addEventListener('click', ()=>{
  btns.forEach(x=>x.classList.remove('active'));
  b.classList.add('active');
  current = b.getAttribute('data-fl');
  // sensible default starting point per field
  if(current==='rot') p0 = [1.0, 0.0];
  if(current==='blow') p0 = [0.8, 0.0];
  if(current==='saddle') p0 = [0.6, 0.6];
  draw();
}));
const FIELDS = {
  rot: {
    v:(x,y)=>[-y, x],
    // closed-form flow: rotation
    phi:(t,x,y)=>[Math.cos(t)*x - Math.sin(t)*y, Math.sin(t)*x + Math.cos(t)*y],
    maxT:(x,y)=> null,
    info: 'X = (−y, x). Integral curves are circles. The flow Φ_t(x,y)=(x cos t − y sin t, x sin t + y cos t) exists for all t ⇒ complete.'
  },
  blow: {
    v:(x,y)=>[x*x, 0],
    phi:(t,x,y)=>{
      // dot x = x^2 ⇒ x(t) = x0/(1 − x0 t); y constant
      const denom = 1 - x*t;
      if(x>0 && t >= 1/x - 1e-6) return [NaN, y];
      if(x<0 && t <= 1/x + 1e-6) return [NaN, y];
      if(Math.abs(denom) < 1e-6) return [NaN, y];
      return [x/denom, y];
    },
    maxT:(x,y)=> x>0 ? 1/x : (x<0 ? 1/x : Infinity),
    info: 'X = (x², 0). Solving ẋ=x², x(0)=x₀>0 gives x(t)=x₀/(1−x₀t), blowing up at t=1/x₀. Max interval: (−∞, 1/x₀) ⇒ incomplete.'
  },
  saddle: {
    v:(x,y)=>[x, -y],
    phi:(t,x,y)=>[x*Math.exp(t), y*Math.exp(-t)],
    maxT:(x,y)=> null,
    info: 'X = (x, −y). Hyperbolic flow: Φ_t(x,y)=(e^t x, e^{-t} y). Complete on ℝ²; integral curves on hyperbolas xy = const.'
  }
};
function draw(){
  svg.innerHTML = '';
  const t = +tSl.value / 50; // [−2, 2]
  tLbl.textContent = `t = ${fmt(t)}`;
  const dx=40, dy=30, dw=440, dh=300;
  svg.appendChild(SVG('rect',{x:dx,y:dy,width:dw,height:dh,fill:'#0b0f16',stroke:'var(--line)',rx:6}));
  const cx=dx+dw/2, cy=dy+dh/2, S=70;
  svg.appendChild(SVG('line',{x1:dx,y1:cy,x2:dx+dw,y2:cy,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:cx,y1:dy,x2:cx,y2:dy+dh,stroke:'var(--line)'}));
  const F = FIELDS[current];
  // Draw background vector field
  for(let xg=-2.6; xg<=2.61; xg+=0.4){
    for(let yg=-1.8; yg<=1.81; yg+=0.3){
      const [vx,vy] = F.v(xg,yg);
      const mag = Math.hypot(vx,vy);
      if(mag < 0.01) continue;
      const sc = 0.2 / Math.max(mag, 0.2);
      const a = [cx + xg*S, cy - yg*S];
      const b = [a[0] + vx*S*sc, a[1] - vy*S*sc];
      if(a[0] < dx+4 || a[0] > dx+dw-4 || a[1] < dy+4 || a[1] > dy+dh-4) continue;
      drawArrow(svg, a, b, {color:'rgba(88,196,221,0.55)',markerId:'fl-bg',width:0.9,pad1:0,pad2:3});
    }
  }
  // Integrate trajectory: sample closed form over many t values
  const N = 120;
  const tmin = Math.min(0, t), tmax = Math.max(0, t);
  const maxLim = F.maxT(p0[0], p0[1]);
  const pts = [];
  for(let i=0;i<=N;i++){
    const tt = tmin + (tmax-tmin)*i/N;
    if(maxLim !== null && maxLim !== Infinity){
      if(maxLim>0 && tt >= maxLim - 1e-3) break;
      if(maxLim<0 && tt <= maxLim + 1e-3) break;
    }
    const [u,v] = F.phi(tt, p0[0], p0[1]);
    if(!isFinite(u) || !isFinite(v)) break;
    const px = cx + u*S, py = cy - v*S;
    if(px < dx-5 || px > dx+dw+5 || py < dy-5 || py > dy+dh+5) break;
    pts.push([px,py]);
  }
  if(pts.length > 1){
    const d = pts.map((p,i)=>(i?'L':'M')+p[0]+' '+p[1]).join(' ');
    svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--yellow)','stroke-width':2.2}));
  }
  // Start point p0 and current Φ_t(p0)
  const pStart = [cx + p0[0]*S, cy - p0[1]*S];
  svg.appendChild(SVG('circle',{cx:pStart[0], cy:pStart[1], r:5, fill:'var(--green)', stroke:'#111','stroke-width':1}));
  const ts = SVG('text',{x:pStart[0]+8, y:pStart[1]-8, 'font-size':12, fill:'var(--green)'}); ts.textContent='p = γ(0)'; svg.appendChild(ts);
  const [ux, uy] = F.phi(t, p0[0], p0[1]);
  if(isFinite(ux) && isFinite(uy)){
    const pNow = [cx + ux*S, cy - uy*S];
    svg.appendChild(SVG('circle',{cx:pNow[0], cy:pNow[1], r:5.5, fill:'var(--pink)', stroke:'#111','stroke-width':1}));
    const tn = SVG('text',{x:pNow[0]+8, y:pNow[1]+4, 'font-size':12, fill:'var(--pink)'}); tn.textContent='Φₜ(p)'; svg.appendChild(tn);
  }
  // side text
  const rx = 540;
  const infoLines = F.info.split('. ');
  infoLines.forEach((s,i)=>{
    const tt = SVG('text',{x:rx, y:40+i*20, 'font-size':12, fill:'var(--mute)'});
    tt.textContent = s.trim() + (i<infoLines.length-1 ? '.' : '');
    svg.appendChild(tt);
  });
  out.textContent =
    `field: ${current}\n`+
    `p = (${fmt(p0[0])}, ${fmt(p0[1])})\n`+
    `t = ${fmt(t)}\n`+
    (isFinite(ux) && isFinite(uy)
      ? `Φₜ(p) = (${fmt(ux)}, ${fmt(uy)})`
      : `Φₜ(p) = undefined (integral curve blew up before t=${fmt(t)})`);
}
// click to reset starting point
svg.addEventListener('click', (e)=>{
  const rect = svg.getBoundingClientRect();
  const vb = svg.viewBox.baseVal;
  const mx = (e.clientX - rect.left) * (vb.width / rect.width);
  const my = (e.clientY - rect.top)  * (vb.height / rect.height);
  const dx=40, dy=30, dw=440, dh=300;
  if(mx<dx || mx>dx+dw || my<dy || my>dy+dh) return;
  const cx=dx+dw/2, cy=dy+dh/2, S=70;
  p0 = [(mx-cx)/S, (cy-my)/S];
  draw();
});
tSl.addEventListener('input', draw);
draw();

