const svg = document.getElementById('br-svg');
const out = document.getElementById('br-out');
const tSl = document.getElementById('br-t');
// Flow of X = (1,0): (x,y) -> (x + s, y)
// Flow of Y = (0, x): dx/ds = 0, dy/ds = x ; so y -> y + x*s (x stays).
function flow(p, s, which){
  const [x,y] = p;
  if(which==='X') return [x + s, y];
  if(which==='Y') return [x, y + x*s];
}
function simulate(t, p0){
  const path = [p0];
  let q = flow(p0, +t, 'X'); path.push(q);
  q = flow(q, +t, 'Y'); path.push(q);
  q = flow(q, -t, 'X'); path.push(q);
  q = flow(q, -t, 'Y'); path.push(q);
  return path;
}
function draw(){
  svg.innerHTML = '';
  const t = +tSl.value / 50; // t in [0.1, 1.9]
  const dx=60, dy=30, dw=440, dh=300;
  svg.appendChild(SVG('rect',{x:dx,y:dy,width:dw,height:dh,fill:'#0b0f16',stroke:'var(--line)',rx:6}));
  const cx=dx+dw/2, cy=dy+dh/2, S=70;
  svg.appendChild(SVG('line',{x1:dx,y1:cy,x2:dx+dw,y2:cy,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:cx,y1:dy,x2:cx,y2:dy+dh,stroke:'var(--line)'}));
  const lx = SVG('text',{x:dx+dw-10,y:cy-6,'font-size':11,fill:'var(--mute)','text-anchor':'end'}); lx.textContent='x'; svg.appendChild(lx);
  const ly = SVG('text',{x:cx+6,y:dy+12,'font-size':11,fill:'var(--mute)'}); ly.textContent='y'; svg.appendChild(ly);

  // Background Y = (0, x): vertical arrows with length prop. to x
  for(let xg=-2; xg<=2.01; xg+=0.4){
    for(let yg=-1.5; yg<=1.5; yg+=0.4){
      const a = [cx + xg*S, cy - yg*S];
      const b = [a[0], a[1] - xg*S*0.2];
      if(Math.abs(xg)<0.02) continue;
      drawArrow(svg, a, b, {color:'rgba(88,196,221,0.35)',markerId:'br-Y',width:0.8,pad1:0,pad2:3});
    }
  }

  // Starting point p0 = (0, 0.3)
  const p0 = [0, 0.3];
  const path = simulate(t, p0);
  const labels = ['p','Φˣₜ p','ΦʸₜΦˣₜ p','Φˣ₋ₜΦʸₜΦˣₜ p','endpoint'];
  const cols  = ['var(--yellow)','var(--yellow)','var(--green)','var(--green)','var(--pink)'];
  const legCols = ['var(--yellow)','var(--cyan)','var(--yellow)','var(--cyan)'];
  for(let i=0;i<path.length-1;i++){
    const A=[cx+path[i][0]*S, cy-path[i][1]*S];
    const B=[cx+path[i+1][0]*S, cy-path[i+1][1]*S];
