// compactly supported bump on (c-w, c+w): exp(-1/(1-((x-c)/w)^2))
function bump(x, c, w){
  const u = (x - c)/w;
  if(Math.abs(u) >= 1) return 0;
  return Math.exp(-1/(1 - u*u));
}
function draw(){
  svg.innerHTML = '';
  const dx=40, dy=20, dw=740, dh=240;
  svg.appendChild(SVG('rect',{x:dx, y:dy, width:dw, height:dh, fill:'#0b0f16', stroke:'var(--line)', rx:6}));
  // axes: x ∈ [-2, 2], y ∈ [0, 1.2]
  const xmin=-2, xmax=2, ymin=0, ymax=1.25;
  const X = x => dx + (x - xmin)/(xmax - xmin) * dw;
  const Y = y => dy + dh - (y - ymin)/(ymax - ymin) * dh;
  // baseline y=1
  svg.appendChild(SVG('line',{x1:X(xmin), y1:Y(1), x2:X(xmax), y2:Y(1),
    stroke:'var(--line)', 'stroke-dasharray':'3 5'}));
  const lblOne = SVG('text',{x:X(xmin)-6, y:Y(1)+4, 'font-size':11, fill:'var(--mute)', 'text-anchor':'end'}); lblOne.textContent='1'; svg.appendChild(lblOne);
  // x-axis
  svg.appendChild(SVG('line',{x1:X(xmin), y1:Y(0), x2:X(xmax), y2:Y(0), stroke:'var(--line)'}));
  // centres
  const cs = [ +c1.value/50, +c2.value/50, +c3.value/50 ]; // each ∈ [-3.6, 3.6]
  const w = 1.2; // support half-width
  const cols = ['var(--cyan)','var(--yellow)','var(--pink)'];
  // sample
  const N = 400;
  const xs = [];
  for(let i=0;i<=N;i++) xs.push(xmin + (xmax-xmin)*i/N);
  const raw = cs.map((c,idx)=> xs.map(x => bump(x, c, w)));
  const sumR = xs.map((_,i)=> raw[0][i] + raw[1][i] + raw[2][i]);
  // If sum vanishes at some x, the renormalisation is undefined; guard with a tiny floor.
  const rho = raw.map(rs => rs.map((r,i)=> sumR[i] > 1e-9 ? r/sumR[i] : 0));
  const sumRho = xs.map((_,i)=> rho[0][i] + rho[1][i] + rho[2][i]);
  // Draw each ρ_i
  for(let k=0;k<3;k++){
    const d = xs.map((x,i)=> (i?'L':'M')+X(x)+' '+Y(rho[k][i])).join(' ');
    svg.appendChild(SVG('path',{d, fill:'none', stroke:cols[k], 'stroke-width':1.8, opacity:0.9}));
    // tick at centre
    svg.appendChild(SVG('line',{x1:X(cs[k]), y1:Y(0)+3, x2:X(cs[k]), y2:Y(0)-3, stroke:cols[k], 'stroke-width':2}));
  }
  // Draw sum
  const dsum = xs.map((x,i)=> (i?'L':'M')+X(x)+' '+Y(sumRho[i])).join(' ');
  svg.appendChild(SVG('path',{d:dsum, fill:'none', stroke:'var(--green)', 'stroke-width':2.4, opacity:0.95}));
  // legend
  const leg = [
    ['ρ₁','var(--cyan)'],
    ['ρ₂','var(--yellow)'],
    ['ρ₃','var(--pink)'],
    ['Σρᵢ','var(--green)']
  ];
  leg.forEach(([t,c],i)=>{
    svg.appendChild(SVG('line',{x1:dx+dw-90, y1:dy+16+i*18, x2:dx+dw-70, y2:dy+16+i*18, stroke:c, 'stroke-width':2}));
    const tt = SVG('text',{x:dx+dw-64, y:dy+20+i*18, 'font-size':11, fill:'var(--mute)'}); tt.textContent=t; svg.appendChild(tt);
  });
  // Check support separation
  const sepOK = (cs[1]-cs[0] < 2*w) && (cs[2]-cs[1] < 2*w) && (cs[0]+w > xmin-0.01) && (cs[2]-w < xmax+0.01);
  out.textContent =
    `centres: c₁=${fmt(cs[0])}, c₂=${fmt(cs[1])}, c₃=${fmt(cs[2])}\n`+
    `support half-width w=${fmt(w)}\n`+
    `covers [−2, 2]?  ${sepOK ? 'yes — supports overlap and Σρᵢ ≡ 1' : 'no — gaps where Σ=0; renormalisation fails there'}\n`+
    `Σρᵢ sample values: ρ(−1)=${fmt(sumRho[Math.round(0.25*N)])}, ρ(0)=${fmt(sumRho[Math.round(0.5*N)])}, ρ(1)=${fmt(sumRho[Math.round(0.75*N)])}`;
}
