const svgC = document.getElementById('or-cyl');
const svgM = document.getElementById('or-mob');
const out = document.getElementById('or-out');
const th = document.getElementById('or-th');
const lbl = document.getElementById('or-lbl');

// Cylinder: core circle of radius R in xz-plane at y=0; section = straight up.
// Parameterise (θ, s) ↦ ((R + s·0)·cos θ, s, (R + 0)·sin θ) with frame (e_θ, e_s)=(tangent to circle, vertical).
// Möbius: section rotates by θ/2 as θ goes around.
// We draw a 2D projection.
function drawStrip(svg, mobius){
  svg.innerHTML = '';
  const w=380, h=260, cx=w/2, cy=h/2, R=80;
  // background
  svg.appendChild(SVG('rect',{x:4, y:4, width:w-8, height:h-8, fill:'#0b0f16', stroke:'var(--line)', rx:6}));
  // core circle (isometric ellipse)
  svg.appendChild(SVG('ellipse',{cx, cy, rx:R, ry:R*0.38, fill:'none', stroke:'var(--line)', 'stroke-dasharray':'3 5'}));
  // strip outline: two curves at s=+1 and s=-1 (for cylinder); for möbius, s=+1 and s=-1 swap over a twist
  const Npts = 60;
  // helper to compute frame+point at angle t (radians)
  function framePt(t, s){
    // core circle point (unrotated frame has tangent along dθ, normal along "vertical")
    const cxs = cx + R*Math.cos(t);
    const cys = cy + R*0.38*Math.sin(t);
    // tangent to circle (unit, 2D)
    const tx = -Math.sin(t), ty = Math.cos(t)*0.38;
    const tlen = Math.hypot(tx,ty); const tux = tx/tlen, tuy = ty/tlen;
    // "outward vertical" in 2D: basically up then rotating if möbius
    // base vertical vector (pointing up on screen) = (0, -1). We rotate by α = (mobius? t/2 : 0)
    const alpha = mobius ? t/2 : 0;
    const bx = Math.sin(alpha)*tux + Math.cos(alpha)*0; // tangent component
    const by = Math.sin(alpha)*tuy + Math.cos(alpha)*(-1);
    // scale by s (section length)
    const sc = 40;
    return {
      base: [cxs, cys],
      point:[cxs + bx*s*sc, cys + by*s*sc],
      tangent:[tux, tuy],
      normal:[bx, by]
    };
  }
  // Two edges
  for(const sSide of [-1, +1]){
    const pts = [];
    for(let i=0;i<=Npts;i++){
      const t = 2*Math.PI*i/Npts;
      const F = framePt(t, sSide);
      pts.push(F.point);
    }
    const d = pts.map((p,i)=>(i?'L':'M')+p[0]+' '+p[1]).join(' ');
    svg.appendChild(SVG('path',{d, fill:'none', stroke: (sSide>0 ? 'var(--cyan)' : 'var(--yellow)'), 'stroke-width':1.5, opacity:0.85}));
  }
  // Frame at angle θ_user
  const tUser = (+th.value) * Math.PI/180;
  const F = framePt(tUser, 0);
  // tangent arrow (green), normal arrow (violet)
  const [bx,by] = F.base;
  const [tux,tuy] = F.tangent;
  const [nx,ny] = F.normal;
  const L = 30;
  svg.appendChild(SVG('circle',{cx:bx, cy:by, r:4, fill:'var(--yellow)', stroke:'#111', 'stroke-width':1}));
  drawArrow(svg, [bx,by], [bx+tux*L, by+tuy*L], {color:'var(--green)', markerId:'or-t'+(mobius?'m':'c'), width:2, pad1:0, pad2:6});
  drawArrow(svg, [bx,by], [bx+nx*L,  by+ny*L ], {color:'var(--violet)',markerId:'or-n'+(mobius?'m':'c'), width:2, pad1:0, pad2:6});
  const lblT = SVG('text',{x:bx+tux*L+6, y:by+tuy*L+4, 'font-size':11, fill:'var(--green)'}); lblT.textContent='e₁'; svg.appendChild(lblT);
  const lblN = SVG('text',{x:bx+nx*L+6,  y:by+ny*L+4,  'font-size':11, fill:'var(--violet)'}); lblN.textContent='e₂'; svg.appendChild(lblN);
  // basepoint label
  const lblB = SVG('text',{x:cx, y:h-14, 'font-size':12, fill:'var(--mute)', 'text-anchor':'middle'});
  lblB.textContent = mobius ? 'Möbius: frame rotates by θ/2 around the strip' : 'Cylinder: frame stays level';
  svg.appendChild(lblB);
}
function draw(){
  drawStrip(svgC, false);
  drawStrip(svgM, true);
  const tDeg = +th.value;
  lbl.textContent = `θ = ${tDeg}°`;
  const closed = tDeg === 360 || tDeg === 0;
  out.textContent =
    `θ = ${tDeg}°\n`+
    `cylinder: e₂ returns to its starting direction at θ=360° ⇒ frame preserved ⇒ orientable.\n`+
    `Möbius:  e₂ rotates by θ/2; at θ=360° it has rotated by 180° ⇒ reflected ⇒ no consistent orientation exists.\n`+
    (closed ? 'loop complete — compare the two frames.' : 'advance the slider to 360° to close the loop.');
}
th.addEventListener('input', draw);
draw();

